INSERT INTO "public"."cancel_reasons" ("code", "label", "description", "allowed_for_staff", "allowed_for_guest", "allowed_for_supervisor", "allow_when_new", "allow_when_in_progress", "requires_comment", "icon", "is_active", "is_terminal", "intent_category") VALUES
	('DUPLICATE_REQUEST', 'Duplicate request', 'Another ticket already exists for the same issue', true, false, true, true, true, true, 'copy', true, true, 'INVALID_REQUEST'),
	('OUTSIDE_OPERATIONAL_SCOPE', 'Outside operational scope', 'Request is not the responsibility of hotel operations', true, false, true, true, true, true, 'slash', true, true, 'OPERATIONAL_CONSTRAINT'),
	('ROOM_OUT_OF_SERVICE', 'Room out of service', 'Room is blocked or unavailable and work is not required', true, false, true, true, true, false, 'lock', true, true, 'OPERATIONAL_CONSTRAINT'),
	('REQUEST_INVALID', 'Invalid request', 'Incorrect service, wrong room, or accidental request', true, false, true, true, true, true, 'alert-circle', true, true, 'INVALID_REQUEST'),
	('RESOLVED_BY_OTHER_DEPARTMENT', 'Resolved by another department', 'Issue was resolved informally by a different team', true, false, true, true, true, true, 'users', true, true, 'RESOLVED_EXTERNALLY'),
	('RESOLVED_OFF_SYSTEM', 'Resolved outside the system', 'Issue was fixed via vendor or manual process without using this ticket', true, false, true, true, true, true, 'tool', true, true, 'RESOLVED_EXTERNALLY'),
	('POLICY_OVERRIDE', 'Policy override', 'Ticket cancelled due to policy decision', false, false, true, true, true, true, 'shield', true, true, 'MANAGEMENT_ACTION'),
	('MANAGEMENT_DECISION', 'Management decision', 'Ticket cancelled by management instruction', false, false, true, true, true, true, 'briefcase', true, true, 'MANAGEMENT_ACTION'),
	('COMPENSATION_PROVIDED', 'Compensation provided', 'Guest compensated and work cancelled', false, false, true, true, true, true, 'gift', true, true, 'MANAGEMENT_ACTION'),
